package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

@Suppress("DEPRECATION")
class SharedFlowToListTest : TestBase() {

    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(acc)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        // Allow emissions to be collected
        yield()

        // Cancel the job
        job.cancel()
        job.join()

        // Verify the list contains the emitted values
        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test
    fun testSharedFlowToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableSetOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toSet(acc)
        }

        // Emit some values (including duplicate)
        sharedFlow.emit(1)
        sharedFlow.emit(2)
        sharedFlow.emit(2)
        sharedFlow.emit(3)

        // Allow emissions to be collected
        yield()

        // Cancel the job
        job.cancel()
        job.join()

        // Verify the set contains the unique emitted values
        assertEquals(setOf(1, 2, 3), acc)
    }

    @Test
    fun testSharedFlowToListPreservesExistingItems() = runTest {
        val sharedFlow = MutableSharedFlow<Int>()
        val acc = mutableListOf(100, 200) // Pre-existing items

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(acc)
        }

        // Emit some values
        sharedFlow.emit(1)
        sharedFlow.emit(2)

        // Allow emissions to be collected
        yield()

        // Cancel the job
        job.cancel()
        job.join()

        // Verify the list contains both pre-existing and newly emitted values
        assertEquals(listOf(100, 200, 1, 2), acc)
    }

    @Test
    fun testSharedFlowWithReplayCache() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 2)

        // Emit values before collector starts
        sharedFlow.emit(10)
        sharedFlow.emit(20)

        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(acc)
        }

        // The replayed values should already be in acc due to UNDISPATCHED
        // Emit more values
        sharedFlow.emit(30)

        // Allow emissions to be collected
        yield()

        // Cancel the job
        job.cancel()
        job.join()

        // Verify the list contains replayed values and new emissions
        assertEquals(listOf(10, 20, 30), acc)
    }
}
"}

