package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

/**
 * Verification test for the SharedFlow.toList(destination) bug fix.
 * 
 * This test verifies that:
 * 1. The destination parameter is actually used (not ignored)
 * 2. Multiple emissions are collected into the same list
 * 3. The fix works for both toList and toSet
 */
@Suppress("DEPRECATION")
class VerifySharedFlowToListFix : TestBase() {

    @Test
    fun testDestinationParameterIsUsed() = runTest {
        val flow = MutableSharedFlow<String>()
        val myList = mutableListOf<String>()

        // Add a marker to prove we're using the same list
        myList.add("MARKER")

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            flow.toList(myList)
        }

        flow.emit("A")
        flow.emit("B")
        yield()

        job.cancel()
        job.join()

        // If destination parameter is ignored, myList would only have ["MARKER"]
        // With the fix, it should have ["MARKER", "A", "B"]
        assertEquals(3, myList.size, "List should have 3 elements")
        assertEquals("MARKER", myList[0], "First element should be MARKER")
        assertEquals("A", myList[1], "Second element should be A")
        assertEquals("B", myList[2], "Third element should be B")
    }

    @Test
    fun testMultipleEmissions() = runTest {
        val flow = MutableSharedFlow<Int>()
        val collected = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            flow.toList(collected)
        }

        // Emit multiple values
        repeat(10) { i ->
            flow.emit(i)
            if (i % 3 == 0) yield()
        }

        job.cancel()
        job.join()

        // All emitted values should be in the list
        assertEquals(10, collected.size)
        assertEquals(List(10) { it }, collected)
    }

    @Test
    fun testToSetDestinationParameter() = runTest {
        val flow = MutableSharedFlow<Int>()
        val mySet = mutableSetOf<Int>()

        // Add marker
        mySet.add(-1)

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            flow.toSet(mySet)
        }

        flow.emit(1)
        flow.emit(2)
        flow.emit(2) // duplicate
        flow.emit(3)
        yield()

        job.cancel()
        job.join()

        // Should have marker plus unique values
        assertEquals(setOf(-1, 1, 2, 3), mySet)
    }
}
"}

